#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Node{
    int op,l,r,k,x,y,idx;
}qu[N<<1],tmp[N<<1];

int n,m,a[N],b[N],ls[N<<1],len,ans[N],c[N];
set<int> s[N<<1];
map<int,int> id;

inline void add(int x,int k){
    for(;x<=n;x+=(x&(-x)))
        c[x]+=k;
}

inline int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

inline void init(int x){
    for(;x<=n && c[x];x+=(x&(-x)))
        c[x]=0;
}

void solve(int ql,int qr,int nl,int nr){
    if(nl==nr){
        for(int i=ql;i<=qr;i++)
            if(qu[i].op==1)
                ans[qu[i].idx]=ls[nl];
        return;
    }
    if(ql>qr)
        return;
    int mid=nl+nr>>1;
    for(int i=nl;i<=mid;i++)
        for(int j:s[i])
            add(j,1);
    int l=ql,r=qr;
    for(int i=ql;i<=qr;i++){
        if(qu[i].op==1){
            int num=ask(qu[i].r)-ask(qu[i].l-1);
            if(num>=qu[i].k)
                tmp[l++]=qu[i];
            else
                tmp[r]=qu[i],tmp[r].k-=num,r--;
        }else if(qu[i].op==2){
            if(nl<=qu[i].y && qu[i].y<=mid)
                add(qu[i].x,1);
            if(qu[i].y<=mid)
                tmp[l++]=qu[i];
            else
                tmp[r--]=qu[i];
        }else{
            if(nl<=qu[i].y && qu[i].y<=mid)
                add(qu[i].x,-1);
            if(qu[i].y<=mid)
                tmp[l++]=qu[i];
            else
                tmp[r--]=qu[i];
        }
    }
    reverse(tmp+r+1,tmp+qr+1);
    for(int i=nl;i<=mid;i++)
        for(int j:s[i])
            init(j);
    for(int i=ql;i<=qr;i++){
        qu[i]=tmp[i];
        if(qu[i].op>1 && nl<=qu[i].y && qu[i].y<=mid)
            init(qu[i].x);
    }
    solve(ql,l-1,nl,mid);
    solve(r+1,qr,mid+1,nr);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        b[i]=a[i];
        ls[++len]=a[i];
    }
    int cnt=0,tot=0;
    for(int i=1;i<=m;i++){
        char s[2];
        scanf("%s",s);
        if(s[0]=='Q'){
            qu[++cnt].op=1;
            scanf("%d%d%d",&qu[cnt].l,&qu[cnt].r,&qu[cnt].k);
            qu[cnt].idx=++tot;
        }else{
            qu[++cnt].op=3;
            int x,y;
            scanf("%d%d",&x,&y);
            qu[cnt].x=x,qu[cnt].y=b[x];
            qu[++cnt].op=2;
            qu[cnt].x=x,qu[cnt].y=y;
            b[x]=y;
            ls[++len]=y;
        }
    }
    /*
    for(int i=1;i<=cnt;i++){
    	printf("%d ",qu[i].op);
    	if(qu[i].op==1)
    		printf("%d %d %d\n",qu[i].l,qu[i].r,qu[i].k);
		else
			printf("%d %d\n",qu[i].x,qu[i].y);
	}
	*/
    sort(ls+1,ls+len+1);
    len=unique(ls+1,ls+len+1)-ls-1;
    for(int i=1;i<=len;i++)
        id[ls[i]]=i;
    for(int i=1;i<=n;i++)
        s[a[i]=id[a[i]]].insert(i);
    for(int i=1;i<=cnt;i++)
        if(qu[i].op>1)
            qu[i].y=id[qu[i].y];
    solve(1,cnt,1,len);
    for(int i=1;i<=tot;i++)
        printf("%d\n",ans[i]);
    return 0;
}
